            container.addString(n.string)
        }
        if (n.isPercussion)
        {
            var articulation: com.omnifret.gplayer.model.InstrumentArticulation? = com.omnifret.gplayer.model.PercussionMapper.getArticulation(n)
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(articulation)) && articulation!!.techniqueSymbolPlacement != com.omnifret.gplayer.model.TechniqueSymbolPlacement.Inside))
            {
                var effectContainer: com.omnifret.gplayer.collections.Map<String, com.omnifret.gplayer.rendering.glyphs.EffectGlyph>
                when (articulation!!.techniqueSymbolPlacement)
                {
                    com.omnifret.gplayer.model.TechniqueSymbolPlacement.Above -> 
                    {
                        effectContainer = this.noteHeads!!.aboveBeatEffects
                    }
                    com.omnifret.gplayer.model.TechniqueSymbolPlacement.Below -> 
                    {
                        effectContainer = this.noteHeads!!.belowBeatEffects
                    }
                    com.omnifret.gplayer.model.TechniqueSymbolPlacement.Outside -> 
                    {
                        effectContainer = outsideBeatEffects
                    }
                    else -> 
                    {
                        return
                    }
                }
                when (articulation!!.techniqueSymbol)
                {
                    com.omnifret.gplayer.model.MusicFontSymbol.PictEdgeOfCymbal -> 
                    {
                        effectContainer.set("PictEdgeOfCymbal", com.omnifret.gplayer.rendering.glyphs.PictEdgeOfCymbalGlyph(0.0, 0.0))
                    }
                    com.omnifret.gplayer.model.MusicFontSymbol.ArticStaccatoAbove -> 
                    {
                        effectContainer.set("ArticStaccatoAbove", com.omnifret.gplayer.rendering.glyphs.ArticStaccatoAboveGlyph(0.0, 0.0))
                    }
                    com.omnifret.gplayer.model.MusicFontSymbol.StringsUpBow -> 
                    {
                        effectContainer.set("StringsUpBow", com.omnifret.gplayer.rendering.glyphs.PickStrokeGlyph(0.0, 0.0, com.omnifret.gplayer.model.PickStroke.Up))
                    }
                    com.omnifret.gplayer.model.MusicFontSymbol.StringsDownBow -> 
                    {
                        effectContainer.set("StringsDownBow", com.omnifret.gplayer.rendering.glyphs.PickStrokeGlyph(0.0, 0.0, com.omnifret.gplayer.model.PickStroke.Down))
                    }
                    com.omnifret.gplayer.model.MusicFontSymbol.GuitarGolpe -> 
                    {
                        effectContainer.set("GuitarGolpe", com.omnifret.gplayer.rendering.glyphs.GuitarGolpeGlyph(0.0, 0.0, true))
                    }
                    else -> { }
                }
            }
        }
    }
    
    public constructor()
        : super()
}

